        if (!referenceClauseState.clause) return;
        const quoteText = `
--- REFERENCE: [${referenceClauseState.clause.code}] ${referenceClauseState.clause.title} ---
${text}
--- END REFERENCE ---
        `.trim();
        insertTextAtCursor(quoteText);
