                                    <div className="flex items-center gap-1">
                                        <button onClick={() => handleRefreshStatus(key.id)} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-slate-800 rounded-lg transition-colors" title="Check Status"><Icon name="RefreshCw" size={14}/></button>
                                        <button onClick={() => handleDeleteKey(key.id)} className="p-1.5 text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-slate-800 rounded-lg transition-colors" title="Delete Key"><Icon name="Trash2" size={14}/></button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </Modal>

            {/* Smart Export Progress Modal */}
            <Modal isOpen={exportState.isOpen} title={exportState.isFinished ? "Export Ready" : "Smart Export Engine"} onClose={() => { if(exportState.isFinished) setExportState(prev => ({...prev, isOpen: false})); }}>
                <div className="space-y-5">
                    {!exportState.isFinished ? (
                        <>
                            <div className="flex items-center justify-between">
                                <span className="text-sm font-bold text-slate-700 dark:text-slate-200">
                                    Processing Chunk {Math.min(exportState.processedChunksCount + 1, exportState.totalChunks)} of {exportState.totalChunks}
                                </span>
                                <span className="text-xs font-mono text-slate-500">{Math.round((exportState.processedChunksCount / exportState.totalChunks) * 100)}%</span>
                            </div>
                            <div className="w-full bg-gray-100 dark:bg-slate-800 rounded-full h-2.5 overflow-hidden">
                                <div className="bg-indigo-600 h-2.5 rounded-full transition-all duration-500" style={{ width: `${(exportState.processedChunksCount / exportState.totalChunks) * 100}%` }}></div>
                            </div>

                            {exportState.isPaused || exportState.error ? (
                                <div className="bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900/30 p-4 rounded-xl animate-in fade-in zoom-in-95">
                                    <div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold mb-2">
                                        <Icon name="AlertCircle" size={18}/>
                                        <h4>Export Paused: Quota Exceeded</h4>
                                    </div>
                                    <p className="text-xs text-slate-600 dark:text-slate-300 mb-4">
                                        All API keys have hit their rate limits. To prevent data loss, please provide a fresh "Rescue Key" to continue immediately.
                                    </p>
                                    <div className="flex gap-2">
                                        <input 
                                            type="text" 
                                            value={rescueKey} 
                                            onChange={(e) => setRescueKey(e.target.value)}
                                            placeholder="Paste fresh API Key here..."
                                            className="flex-1 px-3 py-2 text-xs border border-red-200 dark:border-red-800 rounded-lg outline-none focus:ring-2 focus:ring-red-500"
                                        />
                                        <button 
                                            onClick={handleResumeExport}
                                            disabled={isRescuing}
                                            className="px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg text-xs font-bold transition-all shadow-lg shadow-red-500/30 flex items-center gap-2"
                                        >
                                            {isRescuing ? "Verifying..." : "Rescue & Resume"}
                                        </button>
                                    </div>
                                </div>
                            ) : (
                                <p className="text-xs text-slate-500 dark:text-slate-400 text-center animate-pulse">
                                    AI is optimizing and translating your document...
                                </p>
                            )}
                        </>
                    ) : (
                        <div className="text-center py-4">
                            <div className="w-16 h-16 bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-4 animate-bounce">
                                <Icon name="CheckLineart" size={32}/>
                            </div>
                            <h4 className="text-lg font-bold text-slate-800 dark:text-white mb-2">Export Complete!</h4>
                            <p className="text-sm text-slate-500">Your file has been downloaded successfully.</p>
                            <button onClick={() => setExportState(prev => ({...prev, isOpen: false}))} className="mt-6 px-6 py-2 bg-gray-100 hover:bg-gray-200 dark:bg-slate-800 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-200 rounded-xl font-bold text-sm transition-colors">
                                Close
                            </button>
                        </div>
                    )}
                </div>
            </Modal>

            {/* Command Palette */}
            <CommandPaletteModal 
                isOpen={isCmdPaletteOpen} 
                onClose={() => setIsCmdPaletteOpen(false)} 
                actions={commandActions} 
                onSelectAction={(a: any) => { a.action(); setIsCmdPaletteOpen(false); }} 
            />

            {/* Reference Clause Modal */}
            {referenceClauseState.isOpen && (
                <ReferenceClauseModal 
                    isOpen={referenceClauseState.isOpen} 
                    onClose={() => setReferenceClauseState(prev => ({ ...prev, isOpen: false }))} 
                    clause={referenceClauseState.clause} 
                    standardName={allStandards[standardKey]?.name || standardKey}
                    fullText={referenceClauseState.fullText}
                    isLoading={referenceClauseState.isLoading}
                    onInsert={handleInsertReferenceText}
                />
            )}
        </div>
    );
}

export default App;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import { Icon, AINeuralLoader, SnowOverlay } from './components/UI';
import ReleaseNotesModal from './components/ReleaseNotesModal';
import ReferenceClauseModal from './components/ReferenceClauseModal';
import { STANDARDS_DATA } from './constants';
import { AuditInfo, Clause, StandardsData, AnalysisResult } from './types';
import { generateAnalysis, generateTextReport, fetchFullClauseText } from './services/geminiService';
import mammoth from 'mammoth';

export default function App() {
    // --- Application State ---
    const [sidebarWidth, setSidebarWidth] = useState(320);
    const [isSidebarOpen, setIsSidebarOpen] = useState(true);
    const [layoutMode, setLayoutMode] = useState<'audit' | 'findings' | 'report'>('audit');

    // --- Data State ---
    const [apiKey, setApiKey] = useState(localStorage.getItem('iso_api_key') || (typeof process !== 'undefined' ? process.env.API_KEY : "") || "");
    const [standards, setStandards] = useState<StandardsData>(() => {
        const saved = localStorage.getItem('iso_standards');
        return saved ? JSON.parse(saved) : STANDARDS_DATA;
    });
    const [standardKey, setStandardKey] = useState<string>("ISO 9001:2015");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>({
        company: "", smo: "", department: "", interviewee: "", auditor: "", type: "Internal"
    });
    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // --- Evidence State ---
    const [evidenceText, setEvidenceText] = useState("");
    const [evidenceImages, setEvidenceImages] = useState<{id: string, url: string}[]>([]);

    // --- Analysis State ---
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[]>([]);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [isAnalyzing, setIsAnalyzing] = useState(false);

    // --- Report State ---
    const [finalReportText, setFinalReportText] = useState<string>("");
    const [isReportLoading, setIsReportLoading] = useState(false);
    const [loadingMessage, setLoadingMessage] = useState("");
    const [templateFileName, setTemplateFileName] = useState("");
    const [reportTemplate, setReportTemplate] = useState("");
    const [exportLanguage, setExportLanguage] = useState<'en' | 'vi'>('en');

    // --- Modals State ---
    const [showReleaseNotes, setShowReleaseNotes] = useState(false);
    const [referenceModalOpen, setReferenceModalOpen] = useState(false);
    const [currentRefClause, setCurrentRefClause] = useState<Clause | null>(null);
    const [refClauseText, setRefClauseText] = useState({en: "", vi: ""});
    const [isRefLoading, setIsRefLoading] = useState(false);

    // --- Computed ---
    const hasEvidence = evidenceText.length > 10 || evidenceImages.length > 0;

    // --- Handlers ---

    // Template Upload
    const handleTemplateUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        setTemplateFileName(file.name);

        try {
            if (file.name.endsWith('.docx')) {
                 const arrayBuffer = await file.arrayBuffer();
                 const result = await mammoth.extractRawText({ arrayBuffer });
                 setReportTemplate(result.value);
            } else {
                const text = await file.text();
                setReportTemplate(text);
            }
        } catch (error) {
            console.error("Template upload failed", error);
            alert("Could not read template file.");
        }
    };

    // Generate Analysis
    const handleRunAnalysis = async () => {
        setIsAnalyzing(true);
        try {
            const clauseContext = selectedClauses.join(", "); 
            const prompt = `Analyze the following evidence against clauses ${clauseContext}. Evidence: ${evidenceText}`;
            const systemInstruction = "You are an expert auditor. Return JSON analysis.";

            const resultJson = await generateAnalysis(prompt, systemInstruction, apiKey);
            let parsed = [];
            try { parsed = JSON.parse(resultJson); } catch (e) { console.error(e); }

            setAnalysisResult(Array.isArray(parsed) ? parsed : []);
            if (Array.isArray(parsed)) {
                const sel: Record<string, boolean> = {};
                parsed.forEach((_, i) => sel[i] = true);
                setSelectedFindings(sel);
            }
            setLayoutMode('findings');
        } catch (error) {
            console.error(error);
            alert("Analysis failed. Please check your API Key.");
        } finally {
            setIsAnalyzing(false);
        }
    };

    // Generate Report
    const handleGenerateReport = async () => {
        setIsReportLoading(true);
        setLoadingMessage("Synthesizing Final Report...");
        try {
            const findingsToReport = analysisResult.filter((_, i) => selectedFindings[i]);
            const prompt = `Generate a comprehensive audit report based on these findings: ${JSON.stringify(findingsToReport)}. 
            Context: ${JSON.stringify(auditInfo)}. 
            Template/Style: ${reportTemplate || "Standard ISO Audit Report"}.
            Language: ${exportLanguage === 'vi' ? 'Vietnamese' : 'English'}`;

            const report = await generateTextReport(prompt, "You are a professional lead auditor.", apiKey);
            setFinalReportText(report);
        } catch (error) {
            console.error(error);
            alert("Report generation failed.");
        } finally {
            setIsReportLoading(false);
        }
    };

    // Export
    const startSmartExport = (content: string, type: string, lang: string) => {
        const blob = new Blob([content], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Audit_Report_${lang}_${new Date().toISOString()}.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    // Reference Clause
    const onReferenceClause = async (clause: Clause) => {
        setCurrentRefClause(clause);
        setReferenceModalOpen(true);
        setIsRefLoading(true);
        try {
             const stdName = standards[standardKey]?.name || "Unknown Standard";
             const text = await fetchFullClauseText({code: clause.code, title: clause.title}, stdName, apiKey);
             setRefClauseText(text);
        } catch(e) { console.error(e); }
        setIsRefLoading(false);
    };

    return (
        <div className="flex h-screen w-screen bg-gray-50 dark:bg-slate-950 text-slate-900 dark:text-white overflow-hidden font-sans selection:bg-indigo-100 dark:selection:bg-indigo-900/50">
             <SnowOverlay />
             <Sidebar 
                isOpen={isSidebarOpen}
                width={sidebarWidth}
                setWidth={setSidebarWidth}
                standards={standards}
                standardKey={standardKey}
                setStandardKey={setStandardKey}
                auditInfo={auditInfo}
                setAuditInfo={setAuditInfo}
                selectedClauses={selectedClauses}
                setSelectedClauses={setSelectedClauses}
                onAddNewStandard={() => {}}
                onUpdateStandard={() => {}}
                onResetStandard={() => {}}
                onReferenceClause={onReferenceClause}
             />

             <main className="flex-1 flex flex-col min-w-0 relative h-full">
                {/* Header / Tabs */}
                <div className="h-16 border-b border-gray-200 dark:border-slate-800 flex items-center justify-between px-6 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md z-20">
                    <div className="flex items-center gap-4">
                        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 rounded-lg hover:bg-gray-100 dark:hover:bg-slate-800 text-slate-500">
                            {isSidebarOpen ? <Icon name="CollapsePanel" size={20} /> : <Icon name="ExpandPanel" size={20} />}
                        </button>
                        <div className="flex bg-gray-100 dark:bg-slate-800 rounded-xl p-1">
                            {['audit', 'findings', 'report'].map((m) => (
                                <button 
                                    key={m}
                                    onClick={() => setLayoutMode(m as any)}
                                    className={`px-4 py-1.5 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${layoutMode === m ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                                >
                                    {m}
                                </button>
                            ))}
                        </div>
                    </div>
                    {/* Settings / API Key placeholder */}
                    <div className="flex items-center gap-2">
                        <button onClick={() => setShowReleaseNotes(true)} className="p-2 text-slate-400 hover:text-indigo-500"><Icon name="Info" size={18}/></button>
                    </div>
                </div>

                {/* Content Area */}
                <div className="flex-1 overflow-hidden relative p-4 md:p-6">

                    {/* AUDIT VIEW */}
                    {layoutMode === 'audit' && (
                        <div className="h-full flex flex-col gap-4 animate-in fade-in slide-in-from-bottom-4">
                            <textarea 
                                className="flex-1 w-full p-4 rounded-2xl border border-gray-200 dark:border-slate-800 bg-white dark:bg-slate-900 resize-none outline-none focus:ring-2 ring-indigo-500/20 text-sm font-mono leading-relaxed"
                                placeholder="Paste audit evidence here (interview notes, observation logs, document content)..."
                                value={evidenceText}
                                onChange={e => setEvidenceText(e.target.value)}
                            />
                            <button 
                                onClick={handleRunAnalysis}
                                disabled={!hasEvidence || isAnalyzing}
                                className="h-12 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-indigo-500/20 transition-all active:scale-95 disabled:opacity-50 disabled:active:scale-100"
                            >
                                {isAnalyzing ? <Icon name="Loader" className="animate-spin" /> : <Icon name="Wand2" />}
                                {isAnalyzing ? "Analyzing with Gemini..." : "Analyze Evidence"}
                            </button>
                        </div>
                    )}

                    {/* FINDINGS VIEW */}
                    {layoutMode === 'findings' && (
                        <div className="h-full overflow-y-auto custom-scrollbar animate-in fade-in slide-in-from-bottom-4">
                            {analysisResult.length === 0 ? (
                                <div className="h-full flex flex-col items-center justify-center text-slate-400">
                                    <Icon name="Search" size={48} className="mb-4 opacity-20"/>
                                    <p>No findings yet. Run analysis first.</p>
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    {analysisResult.map((finding, idx) => (
                                        <div key={idx} className="p-4 bg-white dark:bg-slate-900 rounded-2xl border border-gray-100 dark:border-slate-800 flex gap-4">
                                            <input 
                                                type="checkbox" 
                                                checked={!!selectedFindings[idx]} 
                                                onChange={() => setSelectedFindings(prev => ({...prev, [idx]: !prev[idx]}))}
                                                className="mt-1 w-5 h-5 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
                                            />
                                            <div>
                                                <div className="flex items-center gap-2 mb-1">
                                                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded uppercase ${finding.status === 'COMPLIANT' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{finding.status}</span>
                                                    <span className="font-bold text-sm text-slate-700 dark:text-slate-200">{finding.clauseId}</span>
                                                </div>
                                                <p className="text-sm text-slate-600 dark:text-slate-300">{finding.reason}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}

                    {/* REPORT VIEW */}
                    {layoutMode === 'report' && (
                        <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                            {isReportLoading ? (
                                <AINeuralLoader message={loadingMessage}/> 
                            ) : (
                                <> 
                                    <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col">
                                        {!finalReportText ? (
                                            <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60 p-6 text-center">
                                                <Icon name="FileText" size={64} className="mb-4 text-slate-300 dark:text-slate-700"/>
                                                <p className="text-sm font-medium max-w-xs mx-auto">Generate a report from the Findings tab first.</p>
                                            </div> 
                                        ) : (
                                            <textarea className="flex-1 w-full h-full p-6 bg-transparent resize-none focus:outline-none text-slate-700 dark:text-slate-300 font-mono text-sm leading-relaxed" value={finalReportText} onChange={(e) => setFinalReportText(e.target.value)} />
                                        )}
                                    </div>
                                    <div className="flex-shrink-0 flex flex-wrap items-center justify-center md:justify-between gap-4 w-full">
                                        <div className="flex items-center gap-3">
                                            <input type="file" id="template-upload" className="hidden" accept=".txt,.md,.docx" onChange={handleTemplateUpload} />
                                            <label htmlFor="template-upload" className="h-10 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm cursor-pointer">
                                                <Icon name="UploadCloud"/>
                                                <span className="hidden md:inline">{templateFileName ? `Template: ${templateFileName}` : "Upload Template (.docx, .txt)"}</span>
                                            </label>
                                            {templateFileName && <button onClick={() => { setReportTemplate(""); setTemplateFileName(""); }} className="text-red-500 text-xs font-bold">Clear</button>}
                                        </div>
                                        <div className="flex items-center gap-2 md:gap-3">
                                            <button 
                                                onClick={handleGenerateReport} 
                                                disabled={!hasEvidence && (!analysisResult || Object.values(selectedFindings).every(v => !v))} 
                                                className={`h-10 px-3 md:px-5 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 shrink-0 ${hasEvidence || (analysisResult && Object.values(selectedFindings).some(v => v)) ? "bg-indigo-600 text-white shadow-xl active:scale-95 hover:bg-indigo-500" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`} 
                                                title="Synthesize Findings into Report"
                                            >
                                                <Icon name="FileText" size={18}/>
                                                <span className="hidden md:inline">Synthesize Report</span>
                                            </button>
                                            <button 
                                                onClick={() => startSmartExport(finalReportText || "", 'report', exportLanguage)} 
                                                disabled={!finalReportText} 
                                                className="h-10 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50" 
                                                title="Export Final Report"
                                            >
                                                <Icon name="Download"/>
                                                <span className="hidden md:inline">Export Report</span>
                                                <div className="flex ml-1 gap-1">
                                                    <span onClick={(e) => {e.stopPropagation(); setExportLanguage('en');}} className={`px-1 rounded cursor-pointer ${exportLanguage === 'en' ? 'bg-indigo-100 text-indigo-700' : 'text-slate-400'}`}>EN</span>
                                                    <span onClick={(e) => {e.stopPropagation(); setExportLanguage('vi');}} className={`px-1 rounded cursor-pointer ${exportLanguage === 'vi' ? 'bg-indigo-100 text-indigo-700' : 'text-slate-400'}`}>VI</span>
                                                </div>
                                            </button>
                                        </div>
                                    </div>
                                </>
                            )}
                        </div>
                    )}
                </div>
             </main>

             {/* Modals */}
             <ReleaseNotesModal isOpen={showReleaseNotes} onClose={() => setShowReleaseNotes(false)} />
             <ReferenceClauseModal 
                isOpen={referenceModalOpen} 
                onClose={() => setReferenceModalOpen(false)}
                clause={currentRefClause}
                standardName={standards[standardKey]?.name}
                fullText={refClauseText}
                isLoading={isRefLoading}
                onInsert={(text) => setEvidenceText(prev => prev + "\n" + text)}
             />
        </div>
    );
}

