ynthesize} className={`h-10 px-3 md:px-5 rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 shrink-0 flex-1 md:flex-none ${isReadyToSynthesize ? "btn-shrimp shadow-xl active:scale-95" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`} title="Synthesize Findings into Report"><Icon name="FileText" size={18}/><span className="hidden md:inline">Synthesize Report</span><span className="md:hidden">Synthesize</span></button><button onClick={() => startSmartExport(finalReportText || "", 'report', exportLanguage)} disabled={!finalReportText} className="h-10 px-4 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 flex-1 md:flex-none" title="Export Final Report"><Icon name="Download"/><span className="hidden md:inline">Export Report</span><span className="md:hidden">Export</span><div className="lang-pill-container ml-1"><span onClick={(e) => {e.stopPropagation(); setExportLanguage('en');}} className={`lang-pill-btn ${exportLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span><span onClick={(e) => {e.stopPropagation(); setExportLanguage('vi');}} className={`lang-pill-btn ${exportLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span></div></button></div></div></>}</div>}
                    </div>
                </div>
