                                                        <div><label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Evidence</label><input type="text" value={result.evidence} onChange={(e) => handleUpdateFinding(idx, 'evidence', e.target.value)} className="editable-finding-input w-full p-2 rounded-lg border border-gray-100 dark:border-slate-800 bg-white/50 dark:bg-black/10 focus:ring-2 ring-indigo-500/20 outline-none" /></div>
                                                        <div><label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Suggestion</label><input type="text" value={result.suggestion} onChange={(e) => handleUpdateFinding(idx, 'suggestion', e.target.value)} className="editable-finding-input w-full p-2 rounded-lg border border-gray-100 dark:border-slate-800 bg-white/50 dark:bg-black/10 focus:ring-2 ring-indigo-500/20 outline-none" /></div>
                                                        <div><label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Report Conclusion</label><textarea value={result.conclusion_report} onChange={(e) => handleUpdateFinding(idx, 'conclusion_report', e.target.value)} className="editable-finding-input w-full p-2 rounded-lg border border-gray-100 dark:border-slate-800 bg-white/50 dark:bg-black/10 focus:ring-2 ring-indigo-500/20 outline-none h-20" /></div>
