                                                        <div><label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Evidence</label><input type="text" value={result.evidence} onChange={(e) => handleUpdateFinding(idx, 'evidence', e.target.value)} className="editable-finding-input w-full p-2 rounded-lg border border-gray-100 dark:border-slate-800 bg-white/50 dark:bg-black/10 focus:ring-2 ring-indigo-500/20 outline-none" /></div>
                                                        <div><label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Suggestion</label><input type="text" value={result.suggestion} onChange={(e) => handleUpdateFinding(idx, 'suggestion', e.target.value)} className="editable-finding-input w-full p-2 rounded-lg border border-gray-100 dark:border-slate-800 bg-white/50 dark:bg-black/10 focus:ring-2 ring-indigo-500/20 outline-none" /></div>
                                                        <div><label className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">Report Conclusion</label><textarea value={result.conclusion_report} onChange={(e) => handleUpdateFinding(idx, 'conclusion_report', e.target.value)} className="editable-finding-input w-full p-2 rounded-lg border border-gray-100 dark:border-slate-800 bg-white/50 dark:bg-black/10 focus:ring-2 ring-indigo-500/20 outline-none h-20" /></div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    ))}
                                    {isAnalyzeLoading && <div className="flex flex-col items-center justify-center p-8 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 animate-in fade-in duration-500"><AINeuralLoader message={loadingMessage}/></div>}
                                </div>
                                <div className="flex-shrink-0 flex items-center justify-between gap-[5px] mt-2 w-full overflow-x-auto no-scrollbar md:justify-end md:gap-3">
                                    <div className="flex gap-1 bg-gray-100 dark:bg-slate-800 p-1 rounded-xl h-10 items-center shrink-0 flex-1 md:flex-none justify-center">
                                        <button onClick={() => setFindingsViewMode('list')} className={`px-3 h-full flex items-center justify-center gap-2 text-xs font-bold rounded-lg transition-colors flex-1 md:flex-none min-w-[44px] ${findingsViewMode === 'list' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-500 hover:text-indigo-600'}`} title="List View">
                                            <Icon name="LayoutList" size={14}/>
                                            <span className="hidden md:inline">List</span>
                                        </button>
                                        <button onClick={() => setFindingsViewMode('matrix')} className={`px-3 h-full flex items-center justify-center gap-2 text-xs font-bold rounded-lg transition-colors flex-1 md:flex-none min-w-[44px] ${findingsViewMode === 'matrix' ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-white shadow-sm' : 'text-slate-500 hover:text-indigo-600'}`} title="Matrix View">
                                            <Icon name="Grid" size={14}/>
                                            <span className="hidden md:inline">Matrix</span>
                                        </button>
                                    </div>
                                    <button onClick={() => startSmartExport(analysisResult?.filter(r => selectedFindings[r.clauseId]).map(r => `[${r.status}] Clause ${r.clauseId}:\n${r.conclusion_report}`).join('\n\n') || "", 'notes', notesLanguage)} disabled={!analysisResult} className="h-10 px-3 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 shrink-0 flex-1 md:flex-none min-w-[50px]" title="Export Findings">
                                        <Icon name="Download"/>
                                        <span className="hidden md:inline">Export Notes</span>
                                        <div className="lang-pill-container ml-1">
                                            <span onClick={(e) => {e.stopPropagation(); setNotesLanguage('en');}} className={`lang-pill-btn ${notesLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                                            <span onClick={(e) => {e.stopPropagation(); setNotesLanguage('vi');}} className={`lang-pill-btn ${notesLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                                        </div>
                                    </button>
                                </div>
                            </div>
                        )}

                        {/* BLOCK 3: REPORT VIEW */}
                        {layoutMode === 'report' && (
                            <div className="h-full flex flex-col gap-4 animate-fade-in-up">
                                <div className="flex-1 bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-gray-100 dark:border-slate-800 overflow-hidden flex flex-col">
                                    {isReportLoading ? (
                                        <AINeuralLoader message={loadingMessage}/>
                                    ) : finalReportText === null ? (
                                        <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60 p-6 text-center"><Icon name="FileText" size={64} className="mb-4 text-slate-300 dark:text-slate-700"/><p className="text-sm font-medium max-w-xs mx-auto">Generate a report from the Findings tab first.</p></div> 
                                    ) : (
