                if (resultText) {
                    insertTextAtCursor(resultText);
                    setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: resultText } : f));
                } else {
                    throw new Error("No text content extracted.");
                }
            } catch (e: any) {
                console.error("OCR/Processing error:", e);
                const errMsg = e.message?.includes("ALL_KEYS") ? "API Quota Exceeded" : (e.message || "Processing Failed");
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: errMsg } : f));
