                    <>
                        <div className="flex flex-wrap justify-between items-center gap-3">
                            <div className="lang-pill-container shadow-sm border-gray-200">
                                <button onClick={() => setLang('en')} className={`lang-pill-btn ${lang === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>ENGLISH</button>
                                <button onClick={() => setLang('vi')} className={`lang-pill-btn ${lang === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>TIẾNG VIỆT</button>
