                             <h4 className="text-base font-black text-slate-800 dark:text-white leading-tight">{clause.title}</h4>
                        </div>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">{standardName}</p>
                    </div>
                )}

                {isLoading ? (
                    <div className="h-64 flex flex-col items-center justify-center text-slate-500 gap-4">
                        <div className="relative w-16 h-16">
                            <div className="absolute inset-0 border-2 border-indigo-200 dark:border-indigo-800 rounded-full opacity-20"></div>
                            <div className="absolute inset-0 border-t-2 border-indigo-600 rounded-full animate-spin"></div>
                        </div>
                        <span className="text-sm font-bold animate-pulse">Consulting Gemini AI Auditor...</span>
                    </div>
                ) : (
                    <>
                        <div className="flex flex-wrap justify-between items-center gap-3">
                            <div className="lang-pill-container shadow-sm border-gray-200">
                                <button onClick={() => setLang('en')} className={`lang-pill-btn ${lang === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>ENGLISH</button>
                                <button onClick={() => setLang('vi')} className={`lang-pill-btn ${lang === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>TIẾNG VIỆT</button>
                            </div>
                            <div className="flex items-center gap-2">
                                <button 
                                    onClick={handleCopy} 
                                    disabled={isCopied}
                                    className={`p-2.5 bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 rounded-xl font-bold text-xs flex items-center justify-center transition-all hover:scale-110 active:scale-95 disabled:opacity-70 ${isCopied ? 'text-emerald-600 border-emerald-200 bg-emerald-50' : 'text-slate-600 dark:text-slate-300 hover:text-indigo-600'}`}
                                    title={isCopied ? "Copied!" : "Copy to Clipboard"}
                                >
                                    <Icon name={isCopied ? "CheckThick" : "Copy"} size={18}/>
                                </button>
                                <button 
                                    onClick={handleInsert} 
                                    className="p-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-xs flex items-center justify-center transition-all hover:scale-110 active:scale-95 shadow-lg shadow-indigo-500/20"
                                    title="Insert Reference into Evidence"
                                >
                                    <Icon name="Quote" size={18}/>
                                </button>
                            </div>
                        </div>

                        <div className="p-6 h-[400px] overflow-y-auto custom-scrollbar bg-white dark:bg-slate-950 rounded-2xl border border-gray-200 dark:border-slate-800 relative shadow-inner ring-1 ring-black/5">
                            <div className="prose prose-sm dark:prose-invert max-w-none">
                                <p className="text-sm text-slate-800 dark:text-slate-200 whitespace-pre-wrap leading-[1.8] font-medium tracking-tight text-justify">
                                    {streamedText}
                                    {!isLoading && streamedText !== textToDisplay && (
                                        <span className="inline-block w-1.5 h-4 bg-indigo-500 animate-pulse ml-1 align-middle"></span>
                                    )}
                                </p>
                            </div>
                        </div>
                        <div className="text-[9px] text-center text-slate-400 font-bold uppercase tracking-tighter opacity-50">End of Original Standard Text</div>
                    </>
                )}
            </div>
        </Modal>
    );
