import { useEffect, useState } from "react";

export const useDebounce = <T,>(value: T, delay: number): T => {
    const [debouncedValue, setDebouncedValue] = useState(value);
    useEffect(() => {
        const handler = setTimeout(() => {
            setDebouncedValue(value);
        }, delay);
        return () => {
            clearTimeout(handler);
        };
    }, [value, delay]);
    return debouncedValue;
};

export const copyToClipboard = (text: string) => {
    if (!text) return;
    if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).catch(() => fallbackCopy(text));
    } else { fallbackCopy(text); }
};

const fallbackCopy = (text: string) => {
    const textArea = document.createElement("textarea"); textArea.value = text;
    textArea.style.position = "fixed"; textArea.style.left = "-9999px";
    document.body.appendChild(textArea); textArea.focus(); textArea.select();
    try { document.execCommand('copy'); } catch (err) { console.error(err); }
    document.body.removeChild(textArea);
};

export const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve((reader.result as string).split(',')[1]); 
        reader.onerror = error => reject(error);
    });
};

/**
 * CLEANUP ENGINE: Removes markdown artifacts, table markers, and redundant symbols
 * to ensure a professional plain text output.
 */
export const sanitizeTextForExport = (text: string): string => {
    if (!text) return "";
    return text
        // Remove Markdown Table syntax
        .replace(/\|?\s*[:\-]+\s*\|/g, "") 
        .replace(/\|/g, " ")
        // Remove Header symbols but keep text
        .replace(/#{1,6}\s+/g, "")
        // Remove Bold and Italic symbols
        .replace(/\*\*\*/g, "").replace(/\*\*/g, "").replace(/\*/g, "")
        .replace(/___/g, "").replace(/__/g, "").replace(/_/g, "")
        // Remove horizontal lines
        .replace(/^-{3,}/gm, "")
        .replace(/^_{3,}/gm, "")
        // Cleanup redundant empty lines
        .replace(/\n{3,}/g, "\n\n")
        .trim();
};

export const cleanAndParseJSON = (text: string) => {
    if (!text) return null;
    let cleanText = text.trim();
    if (cleanText.startsWith("```")) {
        cleanText = cleanText.replace(/^```(json)?/, "").replace(/```$/, "");
    }
    const firstBracket = cleanText.indexOf('[');
    const firstCurly = cleanText.indexOf('{');
    const lastBracket = cleanText.lastIndexOf(']');
    const lastCurly = cleanText.lastIndexOf('}');
    if (firstBracket !== -1 && lastBracket !== -1 && (firstCurly === -1 || firstBracket < firstCurly)) {
            cleanText = cleanText.substring(firstBracket, lastBracket + 1);
    } else if (firstCurly !== -1 && lastCurly !== -1) {
            cleanText = cleanText.substring(firstCurly, lastCurly + 1);
    }
    try {
        return JSON.parse(cleanText);
    } catch (error) {
        console.error("JSON Parse Error on text:", cleanText);
        return null;
    }
};

export const cleanFileName = (str: string) => {
    if (!str) return 'N_A';
    return str.replace(/[^a-zA-Z0-9\s]/g, '').trim().replace(/\s+/g, '_').substring(0, 30);
};

import { GoogleGenAI, Type } from "@google/genai";
import { DEFAULT_GEMINI_MODEL, DEFAULT_VISION_MODEL } from "../constants";
import { Clause } from "../types";
import { cleanAndParseJSON } from "../utils";

const getAiClient = (overrideKey?: string) => {
    const apiKey = overrideKey || process.env.API_KEY || localStorage.getItem("iso_api_key") || "";
    if (!apiKey) throw new Error("API Key is missing. Please set it in Settings.");
    return new GoogleGenAI({ apiKey });
};

export const validateApiKey = async (key: string, modelId: string = DEFAULT_GEMINI_MODEL): Promise<{ isValid: boolean, latency: number, errorType?: 'invalid' | 'quota_exceeded' | 'unknown' }> => {
    const start = performance.now();
    try {
        const ai = new GoogleGenAI({ apiKey: key });
        await ai.models.generateContent({
            model: modelId,
            contents: "Hi",
            config: {
                maxOutputTokens: 1,
                thinkingConfig: { thinkingBudget: 0 },
            }
        });
        const end = performance.now();
        return { isValid: true, latency: Math.round(end - start) };
    } catch (error: any) {
        let errorType: 'invalid' | 'quota_exceeded' | 'unknown' = 'unknown';
        const msg = error.message?.toLowerCase() || "";
        if (msg.includes("403") || msg.includes("api key not valid") || msg.includes("permission denied")) {
            errorType = 'invalid';
        } else if (msg.includes("429") || msg.includes("quota") || msg.includes("resource exhausted")) {
            errorType = 'quota_exceeded';
        }
        return { isValid: false, latency: 0, errorType };
    }
};

export const fetchFullClauseText = async (clause: { code: string, title: string }, standardName: string, apiKey?: string, model?: string): Promise<{ en: string; vi: string }> => {
    const ai = getAiClient(apiKey);

    // STRATEGIC PROMPT: Forcing professional document structure
    const prompt = `Act as an official ISO Secretariat. Provide the EXACT VERBATIM text for clause: ${standardName} - [${clause.code}] ${clause.title}. 

    FORMATTING REQUIREMENTS:
    - Use clear LINE BREAKS after every paragraph.
    - Each sub-point (a, b, c, etc.) MUST be on a new line and INDENTED.
    - Use BOLD (**) for headings or key terms only.
    - Do NOT wrap in a code block.
    - Maintain a professional document hierarchy.

    Output JSON strictly: {"en": "Text in English...", "vi": "Văn bản tiếng Việt..."}`;

    const response = await ai.models.generateContent({
        model: model || DEFAULT_GEMINI_MODEL,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    en: { type: Type.STRING },
                    vi: { type: Type.STRING }
                },
                required: ["en", "vi"]
            }
        }
    });
    const parsed = cleanAndParseJSON(response.text || "{}");
    return { en: parsed?.en || "N/A", vi: parsed?.vi || "N/A" };
};

export const generateOcrContent = async (textPrompt: string, base64Data: string, mimeType: string, apiKey?: string, model?: string) => {
    const ai = getAiClient(apiKey);
    const response = await ai.models.generateContent({
        model: model || DEFAULT_VISION_MODEL,
        contents: {
            parts: [{ text: textPrompt }, { inlineData: { mimeType, data: base64Data } }]
        }
    });
    return response.text || "";
};

